long long solve(std::vector<std::vector<long long>> edges, std::vector<bool> online, long long k) {
    int n = online.size();
    vector<vector<pair<int, long long>>> adj(n);
    vector<int> in_degree(n, 0);
    for (auto& edge : edges) {
        int u = edge[0];
        int v = edge[1];
        long long c = edge[2];
        adj[u].push_back({v, c});
        in_degree[v]++;
    }

    vector<int> topo;
    queue<int> q;
    for (int i = 0; i < n; ++i) {
        if (in_degree[i] == 0) {
            q.push(i);
        }
    }

    while (!q.empty()) {
        int u = q.front();
        q.pop();
        topo.push_back(u);
        for (auto& [v, c] : adj[u]) {
            in_degree[v]--;
            if (in_degree[v] == 0) {
                q.push(v);
            }
        }
    }

    const long long INF = 1e18;
    vector<long long> best_min(n, -INF);
    vector<long long> best_total(n, INF);
    best_min[0] = INF;
    best_total[0] = 0;

    for (int u : topo) {
        if (!online[u]) continue;
        for (auto& [v, c] : adj[u]) {
            if (!online[v]) continue;
            long long new_min = min(best_min[u], c);
            long long new_total = best_total[u] + c;
            if (new_total > k) continue;
            if (new_min > best_min[v]) {
                best_min[v] = new_min;
                best_total[v] = new_total;
            } else if (new_min == best_min[v] && new_total < best_total[v]) {
                best_total[v] = new_total;
            }
        }
    }

    return best_min[n - 1] == -INF ? -1 : best_min[n - 1];
}
