#include <vector>
#include <queue>
#include <climits>

using namespace std;

long long solve(vector<vector<long long>> edges, vector<bool> online, long long k) {
    int n = online.size();
    vector<vector<pair<int, long long>>> adj(n);
    vector<int> in_degree(n, 0);
    for (auto& e : edges) {
        int u = e[0];
        int v = e[1];
        long long c = e[2];
        adj[u].push_back({v, c});
        in_degree[v]++;
    }

    queue<int> q;
    for (int i = 0; i < n; ++i) {
        if (in_degree[i] == 0) {
            q.push(i);
        }
    }

    vector<int> topo;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        topo.push_back(u);
        for (auto& [v, c] : adj[u]) {
            in_degree[v]--;
            if (in_degree[v] == 0) {
                q.push(v);
            }
        }
    }

    vector<long long> best_min(n, -LLONG_MAX);
    vector<long long> best_total(n, LLONG_MAX);
    best_min[0] = LLONG_MAX;
    best_total[0] = 0;

    for (int u : topo) {
        if (!online[u]) continue;
        for (auto& [v, c] : adj[u]) {
            if (!online[v]) continue;
            long long new_min = min(best_min[u], c);
            long long new_total = best_total[u] + c;
            if (new_total > k) continue;
            if (new_min > best_min[v]) {
                best_min[v] = new_min;
                best_total[v] = new_total;
            } else if (new_min == best_min[v] && new_total < best_total[v]) {
                best_total[v] = new_total;
            }
        }
    }

    return best_min[n - 1] == -LLONG_MAX ? -1 : best_min[n - 1];
}
