from collections import deque

def solve(edges: list[list[int]], online: list[bool], k: int) -> int:
    n = len(online)
    adj = [[] for _ in range(n)]
    in_degree = [0] * n
    for u, v, c in edges:
        adj[u].append((v, c))
        in_degree[v] += 1

    # Kahn's algorithm for topological sort
    q = deque()
    for i in range(n):
        if in_degree[i] == 0:
            q.append(i)
    topo = []
    while q:
        u = q.popleft()
        topo.append(u)
        for v, c in adj[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0:
                q.append(v)

    # Initialize best_min and best_total
    best_min = [-float('inf')] * n
    best_total = [float('inf')] * n
    best_min[0] = float('inf')
    best_total[0] = 0

    for u in topo:
        if not online[u]:
            continue
        for v, c in adj[u]:
            if not online[v]:
                continue
            new_min = min(best_min[u], c)
            new_total = best_total[u] + c
            if new_total > k:
                continue
            if new_min > best_min[v]:
                best_min[v] = new_min
                best_total[v] = new_total
